VALUES
  ('promotion-6ec17a12-moex-00028', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '關於行政執行之敘述，下列何者錯誤？', '["行政機關依法作成行政處分，課予人民義務，不表示即可以強制手段貫徹之，因此行政執行須 另有法律依據，且須符合動用強制手段之法定要件與程序", "行政機關於動用強制手段前，須於處分書或另以書面限定相當之履行期限，並告知不履行之後果", "行政強制措施若涉及剝奪人民身體自由者，例如管收，基於憲法第8條之規定，須經法院始得 為之", "行為或不行為義務之執行，由原處分機關或該管行政機關為之；公法上金錢給付義務逾期不履 行者，亦同 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、70130 71130"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "131", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00029', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '關於政府資訊公開法之敘述，下列何者正確？', '["申請人對於政府機關就其申請提供政府資訊所為之決定不服者，不得提起行政救濟", "政府機關提供政府資訊時，得按申請政府資訊之用途，向申請人收取費用", "申請政府機關提供政府資訊，以具有中華民國國籍者為限", "人民請求政府資訊公開，以維護其法律上利益有必要者為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "131", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00030', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '依司法實務見解，受理訴願機關撤銷原行政處分之全部時，下列敘述何者正確？', '["訴願管轄機關得逕為更不利益之變更決定，如發回原行政處分機關另為處分時亦得為更不利益 之處分", "訴願管轄機關不得為更不利益之變更決定，但發回原行政處分機關另為處分時得為更不利益之 處分", "訴願管轄機關得逕為更不利益之變更決定，但發回原行政處分機關另為處分時不得為更不利益 之處分", "訴願管轄機關不得逕為更不利益之變更決定，如發回原處分行政機關另為處分時亦不得為更不 利益之處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "131", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00031', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '關於訴願審議委員會之敘述，下列何者正確？', '["各機關辦理訴願事件，應設訴願審議委員會，組成人員以具有法制專長者為限", "訴願審議委員會委員，由本機關高級職員及遴聘社會公正人士、學者、專家擔任之；其中社會 公正人士、學者、專家人數不得少於三分之一", "訴願決定應經訴願審議委員會會議之決議，其決議以委員三分之二之出席，出席委員過半數之 同意行之", "訴願審議委員會主任委員或委員對於訴願事件有利害關係者，應自行迴避，不得參與審議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "131", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
